+import type { AnyColumn } from '~/column.ts';
+import type { SQL, SQLWrapper } from '../sql.ts';
+import { sql } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type WindowExpression<T> = SQL<T> & { over(spec?: WindowSpec | string): SQL<T> };
+
+export type FrameBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { readonly type: 'preceding' | 'following'; readonly value: number };
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function validateOffset(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+}
+
+export function preceding(value: number): FrameBoundary {
+	validateOffset('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): FrameBoundary {
+	validateOffset('following', value);
+	return { type: 'following', value };
+}
+
+function boundaryOrder(boundary: FrameBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function frame(type: WindowFrame['type'], spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) throw new Error('Window frame from boundary must not be ordered after to boundary');
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame { return frame('range', spec); }
+
+function renderBoundary(boundary: FrameBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === currentRow) return sql.raw('current row');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	return sql.raw(`${boundary.value} ${boundary.type}`);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const chunks: SQL[] = [];
+	if (spec.partitionBy) chunks.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	if (spec.orderBy) chunks.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	if (spec.frame) chunks.push(sql`${sql.raw(spec.frame.type)} between ${renderBoundary(spec.frame.from)} and ${renderBoundary(spec.frame.to)}`);
+	return sql.join(chunks, sql` `);
+}
+
+function windowFunction<T>(expression: SQL<T>): WindowExpression<T> {
+	return Object.assign(expression, {
+		over(spec: WindowSpec | string = {}): SQL<T> {
+			return typeof spec === 'string' ? sql`${expression} over ${sql.identifier(spec)}` : sql`${expression} over (${buildWindowSpec(spec)})`;
+		},
+	});
+}
+
+function positional(name: string, value: number): SQL { return sql.raw(String(value)); }
+function positive(name: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`);
+}
+
+export function rowNumber(): WindowExpression<number> { return windowFunction(sql<number>`row_number()`); }
+export function rank(): WindowExpression<number> { return windowFunction(sql<number>`rank()`); }
+export function denseRank(): WindowExpression<number> { return windowFunction(sql<number>`dense_rank()`); }
+export function ntile(buckets: number): WindowExpression<number> { positive('ntile', buckets); return windowFunction(sql<number>`ntile(${positional('ntile', buckets)})`); }
+export function percentRank(): WindowExpression<number> { return windowFunction(sql<number>`percent_rank()`); }
+export function cumeDist(): WindowExpression<number> { return windowFunction(sql<number>`cume_dist()`); }
+
+export function lag<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowExpression<Exclude<WindowValue<T>, null>>;
+export function lag<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: unknown): WindowExpression<WindowValue<T> | null> {
+	return windowFunction(sql`${sql.raw('lag')}(${value}${offset === undefined ? undefined : sql`, ${positional('lag', offset)}`}${defaultValue === undefined ? undefined : sql`, ${defaultValue}`})`) as any;
+}
+export function lead<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper, TDefault>(value: T, offset: number | undefined, defaultValue: TDefault): WindowExpression<Exclude<WindowValue<T>, null>>;
+export function lead<T extends SQLWrapper>(value: T, offset?: number, defaultValue?: unknown): WindowExpression<WindowValue<T> | null> {
+	return windowFunction(sql`${sql.raw('lead')}(${value}${offset === undefined ? undefined : sql`, ${positional('lead', offset)}`}${defaultValue === undefined ? undefined : sql`, ${defaultValue}`})`) as any;
+}
+export function firstValue<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null> { return windowFunction(sql`first_value(${value})`); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null> { return windowFunction(sql`last_value(${value})`); }
+export function nthValue<T extends SQLWrapper>(value: T, nth: number): WindowExpression<WindowValue<T> | null> { positive('nthValue', nth); return windowFunction(sql`nth_value(${value}, ${positional('nthValue', nth)})`); }
+export function windowSum<T extends SQLWrapper>(value: T): WindowExpression<string | null> { return windowFunction(sql<string | null>`sum(${value})`); }
+export function windowAvg<T extends SQLWrapper>(value: T): WindowExpression<string | null> { return windowFunction(sql<string | null>`avg(${value})`); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null> { return windowFunction(sql<WindowValue<T> | null>`min(${value})`); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowExpression<WindowValue<T> | null> { return windowFunction(sql<WindowValue<T> | null>`max(${value})`); }
+export function windowCount(value?: SQLWrapper): WindowExpression<number> { return windowFunction(sql<number>`count(${value ?? sql.raw('*')})`); }
