+import { expect, test } from 'vitest';
+
+import { PgDialect } from '~/pg-core/dialect.ts';
+import { QueryBuilder } from '~/pg-core/query-builders/query-builder.ts';
+import {
+	currentRow,
+	following,
+	lag,
+	nthValue,
+	ntile,
+	preceding,
+	range,
+	rowNumber,
+	rows,
+	windowCount,
+} from '~/sql/functions/window.ts';
+import { sql } from '~/sql/sql.ts';
+
+const dialect = new PgDialect();
+
+test('window expressions render positional arguments inline', () => {
+	const query = dialect.sqlToQuery(
+		sql`${ntile(4).over()} ${nthValue(sql`value`, 2).over({ orderBy: sql`value` })} ${lag(sql`value`, 0).over()}`,
+	);
+	expect(query.sql).toBe('ntile(4) over () nth_value(value, 2) over (order by value) lag(value, 0) over ()');
+	expect(query.params).toEqual([]);
+});
+
+test('window frames and named window definitions render correctly', () => {
+	const query = new QueryBuilder()
+		.select({ number: rowNumber().over('ordered'), count: windowCount().over('ordered') })
+		.from(sql`items`)
+		.window('ordered', {
+			partitionBy: sql`group_id`,
+			orderBy: sql`value`,
+			frame: rows({ from: preceding(2), to: currentRow }),
+		})
+		.orderBy(sql`value`)
+		.toSQL();
+	expect(query.sql).toBe('select row_number() over "ordered", count(*) over "ordered" from items window "ordered" as (partition by group_id order by value rows between 2 preceding and current row) order by value');
+});
+
+test('window helpers validate invalid input', () => {
+	expect(() => ntile(0)).toThrow(/ntile.*0/);
+	expect(() => nthValue(sql`value`, -1)).toThrow(/nthValue.*-1/);
+	expect(() => preceding(-1)).toThrow(/preceding/);
+	expect(() => following(1.5)).toThrow(/following/);
+	expect(() => rows({ from: following(1), to: currentRow })).toThrow(/from/);
+	expect(() => range({ from: currentRow, to: preceding(1) })).toThrow(/from/);
+});
